{"content":"1: import { useRef } from 'react';
2: 
3: import { fromUnixTime, isAfter } from 'date-fns';
4: import { c } from 'ttag';
5: 
6: import type { PrivateKeyReference, SessionKey } from '@proton/crypto';
7: import { CryptoProxy, VERIFICATION_STATUS } from '@proton/crypto';
8: import { queryFileRevision, queryFileRevisionThumbnail } from '@proton/shared/lib/api/drive/files';
9: import { queryGetLink } from '@proton/shared/lib/api/drive/link';
10: import { RESPONSE_CODE } from '@proton/shared/lib/drive/constants';
11: import type {
12:     DriveFileRevisionResult,
13:     DriveFileRevisionThumbnailResult,
14: } from '@proton/shared/lib/interfaces/drive/file';
15: import type { LinkMetaResult } from '@proton/shared/lib/interfaces/drive/link';
16: import { decryptSigned } from '@proton/shared/lib/keys/driveKeys';
17: import type { VerificationKeysCallback } from '@proton/shared/lib/keys/drivePassphrase';
18: import { decryptPassphrase, getDecryptedSessionKey } from '@proton/shared/lib/keys/drivePassphrase';
19: 
20: import { isIgnoredError, isIgnoredErrorForReporting, sendErrorReport } from '../../utils/errorHandling';
21: import { EnrichedError } from '../../utils/errorHandling/EnrichedError';
22: import { getIsPublicContext } from '../../utils/getIsPublicContext';
23: import type { MetricUserPlan } from '../../utils/type/MetricTypes';
24: import { tokenIsValid } from '../../utils/url/token';
25: import { linkMetaToEncryptedLink, revisionPayloadToRevision, useDebouncedRequest } from '../_api';
26: import type { IntegrityMetrics, VerificationKey } from '../_crypto';
27: import { integrityMetrics, useDriveCrypto } from '../_crypto';
28: import {
29:     type Share,
30:     ShareType,
31:     type ShareTypeStringWithPublic,
32:     type ShareWithKey,
33:     getShareTypeString,
34:     useDefaultShare,
35:     useShare,
36: } from '../_shares';
37: import { useDirectSharingInfo } from '../_shares/useDirectSharingInfo';
38: import { useGetMetricsUserPlan } from '../_user/useGetMetricsUserPlan';
39: import { useDebouncedFunction } from '../_utils';
40: import { decryptExtendedAttributes } from './extendedAttributes';
41: import type { DecryptedLink, EncryptedLink, SignatureIssueLocation, SignatureIssues } from './interface';
42: import { isDecryptedLinkSame } from './link';
43: import useLinksKeys from './useLinksKeys';
44: import useLinksState from './useLinksState';
45: 
46: // Interval should not be too low to not cause spikes on the server but at the
47: // same time not too high to not overflow available memory on the device.
48: const FAILING_FETCH_BACKOFF_MS = 10 * 60 * 1000; // 10 minutes.
49: const generateCorruptDecryptedLink = (encryptedLink: EncryptedLink, name: string): DecryptedLink => ({
50:     encryptedName: encryptedLink.name,
51:     name,
52:     type: encryptedLink.type,
53:     linkId: encryptedLink.linkId,
54:     createTime: encryptedLink.createTime,
55:     corruptedLink: true,
56:     activeRevision: encryptedLink.activeRevision,
57:     digests: { sha1: '' },
58:     hash: encryptedLink.hash,
59:     size: encryptedLink.size,
60:     originalSize: encryptedLink.size,
61:     fileModifyTime: encryptedLink.metaDataModifyTime,
62:     metaDataModifyTime: encryptedLink.metaDataModifyTime,
63:     isFile: encryptedLink.isFile,
64:     mimeType: encryptedLink.mimeType,
65:     hasThumbnail: encryptedLink.hasThumbnail,
66:     isShared: encryptedLink.isShared,
67:     parentLinkId: encryptedLink.parentLinkId,
68:     rootShareId: encryptedLink.rootShareId,
69:     signatureIssues: encryptedLink.signatureIssues,
70:     originalDimensions: {
71:         height: 0,
72:         width: 0,
73:     },
74:     trashed: encryptedLink.trashed,
75:     volumeId: encryptedLink.volumeId,
76: });
77: 
78: export default function useLink() {
79:     const linksKeys = useLinksKeys();
80:     const linksState = useLinksState();
81:     const { getVerificationKey } = useDriveCrypto();
82:     const { getSharePrivateKey, getShare } = useShare();
83:     const { getDefaultShareAddressEmail } = useDefaultShare();
84:     const { getDirectSharingInfo } = useDirectSharingInfo();
85: 
86:     const userPlan = useGetMetricsUserPlan();
87: 
88:     const debouncedRequest = useDebouncedRequest();
89:     const fetchLink = async (abortSignal: AbortSignal, shareId: string, linkId: string): Promise<EncryptedLink> => {
90:         const { Link } = await debouncedRequest<LinkMetaResult>(
91:             {
92:                 ...queryGetLink(shareId, linkId),
93:                 // Ignore HTTP errors (e.g. "Not Found", "Unprocessable Entity"
94:                 // etc). Not every `fetchLink` call relates to a user action
95:                 // (it might be a helper function for a background job). Hence,
96:                 // there are potential cases when displaying such messages will
97:                 // confuse the user. Every higher-level caller should handle it
98:                 // based on the context.
99:                 silence: true,
100:             },
101:             abortSignal
102:         );
103:         return linkMetaToEncryptedLink(Link, shareId);
104:     };
105: 
106:     return useLinkInner(
107:         fetchLink,
108:         linksKeys,
109:         linksState,
110:         getVerificationKey,
111:         getSharePrivateKey,
112:         getShare,
113:         getDefaultShareAddressEmail,
114:         getDirectSharingInfo,
115:         userPlan,
116:         integrityMetrics,
117:         CryptoProxy.importPrivateKey
118:     );
119: }
120: 
121: export function useLinkInner(
122:     fetchLink: (abortSignal: AbortSignal, shareId: string, linkId: string) => Promise<EncryptedLink>,
123:     linksKeys: Pick<
124:         ReturnType<typeof useLinksKeys>,
125:         | 'getPassphrase'
126:         | 'setPassphrase'
127:         | 'getPassphraseSessionKey'
128:         | 'setPassphraseSessionKey'
129:         | 'getPrivateKey'
130:         | 'setPrivateKey'
131:         | 'getSessionKey'
132:         | 'setSessionKey'
133:         | 'getHashKey'
134:         | 'setHashKey'
135:     >,
136:     linksState: Pick<ReturnType<typeof useLinksState>, 'getLink' | 'setLinks' | 'setCachedThumbnail'>,
137:     getVerificationKey: ReturnType<typeof useDriveCrypto>['getVerificationKey'],
138:     getSharePrivateKey: ReturnType<typeof useShare>['getSharePrivateKey'],
139:     getShare: ReturnType<typeof useShare>['getShare'],
140:     getDefaultShareAddressEmail: ReturnType<typeof useDefaultShare>['getDefaultShareAddressEmail'],
141:     getDirectSharingInfo: ReturnType<typeof useDirectSharingInfo>['getDirectSharingInfo'],
142:     userPlan: MetricUserPlan,
143:     integrityMetrics: IntegrityMetrics,
144:     importPrivateKey: typeof CryptoProxy.importPrivateKey // passed as arg for easier mocking when testing
145: ) {
146:     const debouncedFunction = useDebouncedFunction();
147:     const debouncedRequest = useDebouncedRequest();
148: 
149:     // Cache certain API errors in order to avoid sending multiple requests to
150:     // the same failing link. For example, trying to fetch the same missing
151:     // parent link for multiple descendants (when processing already outdated
152:     // events).
153:     const linkFetchErrors = useRef<{ [key: string]: any }>({});
154: 
155:     const fetchLinkDONOTUSE = fetchLink;
156:     fetchLink = async (abortSignal: AbortSignal, shareId: string, linkId: string): Promise<EncryptedLink> => {
157:         const err = linkFetchErrors.current[shareId + linkId];
158:         if (err) {
159:             throw err;
160:         }
161: 
162:         return fetchLinkDONOTUSE(abortSignal, shareId, linkId).catch((err) => {
163:             if (
164:                 [RESPONSE_CODE.NOT_FOUND, RESPONSE_CODE.NOT_ALLOWED, RESPONSE_CODE.INVALID_ID].includes(err?.data?.Code)
165:             ) {
166:                 linkFetchErrors.current[shareId + linkId] = err;
167:                 setTimeout(() => {
168:                     delete linkFetchErrors.current[shareId + linkId];
169:                 }, FAILING_FETCH_BACKOFF_MS);
170:             }
171:             throw err;
172:         });
173:     };
174: 
175:     const loadShareTypeString = async (shareId: string): Promise<ShareTypeStringWithPublic> => {
176:         if (getIsPublicContext()) {
177:             return 'shared_public';
178:         }
179:         return (
180:             getShare(new AbortController().signal, shareId)
181:                 .then(getShareTypeString)
182:                 // getShare should be fast call as share is already cached by this time.
183:                 // In case of failure, fallback 'shared' is good assumption as it might
184:                 // mean some edge case for sharing.
185:                 // After refactor, this should be handled better.
186:                 .catch(() => 'shared')
187:         );
188:     };
189: 
190:     const handleDecryptionError = (shareId: string, encryptedLink: EncryptedLink) => {
191:         void loadShareTypeString(shareId).then((shareType) => {
192:             const options = {
193:                 plan: userPlan,
194:                 createTime: encryptedLink.createTime,
195:             };
196:             integrityMetrics.nodeDecryptionError(encryptedLink.linkId, shareType, options);
197:         });
198:     };
199: 
200:     const reportSignatureError = (shareId: string, encryptedLink: EncryptedLink, location: SignatureIssueLocation) => {
201:         // This means that the shareId is a token for a public link (bookmarking) and does not need signatureCheck
202:         // Exemple:
203:         // - shareId: D4TVgdFKidFgQWd5IeXYyegjDNV9KWF1HDwjxZlesUo-Wc2NTL8mUQc6IlYwowznc5vHQkTL4iUbn6K0CorrjQ==
204:         // - token: 2NR85F8NSC
205:         if (tokenIsValid(shareId)) {
206:             return;
207:         }
208:         void loadShareTypeString(shareId).then(async (shareType) => {
209:             const email = await getDefaultShareAddressEmail();
210:             const verificationKey = {
211:                 passphrase: 'SignatureEmail',
212:                 hash: 'NodeKey',
213:                 name: 'NameSignatureEmail',
214:                 xattrs: 'SignatureEmail',
215:                 contentKeyPacket: 'NodeKey',
216:                 blocks: 'NodeKey',
217:                 thumbnail: 'NodeKey',
218:                 manifest: 'NodeKey',
219:             }[location] as VerificationKey;
220: 
221:             const options = {
222:                 plan: userPlan,
223:                 createTime: encryptedLink.createTime,
224:                 addressMatchingDefaultShare: encryptedLink.signatureEmail === email,
225:             };
226:             integrityMetrics.signatureVerificationError(encryptedLink.linkId, shareType, verificationKey, options);
227:         });
228:     };
229: 
230:     const handleSignatureCheck = (
231:         shareId: string,
232:         encryptedLink: EncryptedLink,
233:         location: SignatureIssueLocation,
234:         verificationStatus: VERIFICATION_STATUS
235:     ) => {
236:         if (verificationStatus !== VERIFICATION_STATUS.SIGNED_AND_VALID) {
237:             const signatureIssues: SignatureIssues = {};
238:             signatureIssues[location] = verificationStatus;
239:             linksState.setLinks(shareId, [
240:                 {
241:                     encrypted: {
242:                         ...encryptedLink,
243:                         signatureIssues,
244:                     },
245:                 },
246:             ]);
247: 
248:             reportSignatureError(shareId, encryptedLink, location);
249:         }
250:     };
251: 
252:     /**
253:      * debouncedFunctionDecorator wraps original callback with debouncedFunction
254:      * to ensure that if even two or more calls with the same parameters are
255:      * executed only once. E.g., to not decrypt the same link keys twice.
256:      */
257:     const debouncedFunctionDecorator = <T>(
258:         cacheKey: string,
259:         callback: (abortSignal: AbortSignal, shareId: string, linkId: string) => Promise<T>
260:     ): ((abortSignal: AbortSignal, shareId: string, linkId: string) => Promise<T>) => {
261:         const wrapper = async (abortSignal: AbortSignal, shareId: string, linkId: string): Promise<T> => {
262:             return debouncedFunction(
263:                 async (abortSignal: AbortSignal) => {
264:                     return callback(abortSignal, shareId, linkId);
265:                 },
266:                 [cacheKey, shareId, linkId],
267:                 abortSignal
268:             );
269:         };
270:         return wrapper;
271:     };
272: 
273:     const getEncryptedLink = debouncedFunctionDecorator(
274:         'getEncryptedLink',
275:         async (abortSignal: AbortSignal, shareId: string, linkId: string): Promise<EncryptedLink> => {
276:             const cachedLink = linksState.getLink(shareId, linkId);
277:             if (cachedLink) {
278:                 return cachedLink.encrypted;
279:             }
280:             const link = await fetchLink(abortSignal, shareId, linkId);
281:             linksState.setLinks(shareId, [{ encrypted: link }]);
282:             return link;
283:         }
284:     );
285: 
286:     /**
287:      * getLinkPassphraseAndSessionKey returns the passphrase with session key
288:      * used for locking the private key.
289:      */
290:     const getLinkPassphraseAndSessionKey = debouncedFunctionDecorator(
291:         'getLinkPassphraseAndSessionKey',
292:         async (
293:             abortSignal: AbortSignal,
294:             shareId: string,
295:             linkId: string
296:         ): Promise<{ passphrase: string; passphraseSessionKey: SessionKey; encryptedLink?: EncryptedLink }> => {
297:             const passphrase = linksKeys.getPassphrase(shareId, linkId);
298:             const sessionKey = linksKeys.getPassphraseSessionKey(shareId, linkId);
299:             if (passphrase && sessionKey) {
300:                 return { passphrase, passphraseSessionKey: sessionKey };
301:             }
302: 
303:             const encryptedLink = await getEncryptedLink(abortSignal, shareId, linkId);
304: 
305:             let privateKey: PrivateKeyReference | undefined;
306:             let privateKeyError;
307: 
308:             try {
309:                 const parentPrivateKey = encryptedLink.parentLinkId
310:                     ? // eslint-disable-next-line @typescript-eslint/no-use-before-define
311:                       await getLinkPrivateKey(abortSignal, shareId, encryptedLink.parentLinkId)
312:                     : await getSharePrivateKey(abortSignal, shareId);
313:                 privateKey = parentPrivateKey;
314:             } catch (e) {
315:                 privateKeyError = e;
316:                 // ignore failures but still report them to Sentry
317:                 sendErrorReport(e, {
318:                     extra: {
319:                         message: 'getLinkPassphraseAndSessionKey() - Failed to get parentPrivateKey',
320:                     },
321:                 });
322:             }
323: 
324:             if (encryptedLink.photoProperties?.albums.length && !encryptedLink.parentLinkId) {
325:                 for (const album of encryptedLink.photoProperties.albums) {
326:                     try {
327:                         // eslint-disable-next-line @typescript-eslint/no-use-before-define
328:                         const albumPrivateKey = await getLinkPrivateKey(abortSignal, shareId, album.albumLinkId);
329:                         privateKey = albumPrivateKey;
330:                         // we can break at first album since it's enough to decrypt / for optimization
331:                         break;
332:                     } catch (e) {
333:                         // ignore failures but still report them to Sentry
334:                         sendErrorReport(e, {
335:                             extra: {
336:                                 message: 'getLinkPassphraseAndSessionKey() - Failed to get albumPrivateKey',
337:                             },
338:                         });
339:                     }
340:                 }
341:             }
342: 
343:             if (!privateKey) {
344:                 if (abortSignal.aborted) {
345:                     throw privateKeyError;
346:                 }
347:                 // This should never happen. If you see this error in Sentry something is wrong
348:                 throw new EnrichedError('No private key was found during getLinkPassphraseAndSessionKey', {
349:                     tags: {
350:                         shareId,
351:                         linkId,
352:                     },
353:                     extra: { e: privateKeyError, crypto: true },
354:                 });
355:             }
356: 
357:             const addressPublicKey = encryptedLink.signatureEmail
358:                 ? await getVerificationKey(encryptedLink.signatureEmail)
359:                 : [];
360: 
361:             try {
362:                 // Fallback to parent NodeKey in case if we don't have addressPublicKey (Anonymous upload)
363:                 const publicKeysCallbackList: VerificationKeysCallback[] = [
364:                     async () => (encryptedLink.signatureEmail ? addressPublicKey : [privateKey]),
365:                 ];
366: 
367:                 const {
368:                     decryptedPassphrase,
369:                     sessionKey: passphraseSessionKey,
370:                     verificationStatus,
371:                 } = await decryptPassphrase({
372:                     armoredPassphrase: encryptedLink.nodePassphrase,
373:                     armoredSignature: encryptedLink.nodePassphraseSignature,
374:                     privateKeys: [privateKey],
375:                     publicKeysCallbackList,
376:                 });
377: 
378:                 handleSignatureCheck(shareId, encryptedLink, 'passphrase', verificationStatus);
379: 
380:                 linksKeys.setPassphrase(shareId, linkId, decryptedPassphrase);
381:                 linksKeys.setPassphraseSessionKey(shareId, linkId, passphraseSessionKey);
382: 
383:                 return {
384:                     passphrase: decryptedPassphrase,
385:                     passphraseSessionKey,
386:                     encryptedLink,
387:                 };
388:             } catch (e) {
389:                 throw new EnrichedError('Failed to decrypt link passphrase', {
390:                     tags: {
391:                         shareId,
392:                         linkId,
393:                     },
394:                     extra: { e, crypto: true },
395:                 });
396:             }
397:         }
398:     );
399: 
400:     /**
401:      * getLinkPrivateKey returns the private key used for link meta data encryption.
402:      */
403:     const getLinkPrivateKey = debouncedFunctionDecorator(
404:         'getLinkPrivateKey',
405:         async (abortSignal: AbortSignal, shareId: string, linkId: string): Promise<PrivateKeyReference> => {
406:             let privateKey = linksKeys.getPrivateKey(shareId, linkId);
407:             if (privateKey) {
408:                 return privateKey;
409:             }
410: 
411:             // getLinkPassphraseAndSessionKey already call getEncryptedLink, prevent to call fetchLink twice
412:             let { passphrase, encryptedLink } = await getLinkPassphraseAndSessionKey(abortSignal, shareId, linkId);
413:             encryptedLink = encryptedLink || (await getEncryptedLink(abortSignal, shareId, linkId));
414:             try {
415:                 privateKey = await importPrivateKey({ armoredKey: encryptedLink.nodeKey, passphrase });
416:             } catch (e) {
417:                 throw new EnrichedError('Failed to import link private key', {
418:                     tags: {
419:                         shareId,
420:                         linkId,
421:                     },
422:                     extra: { e, crypto: true },
423:                 });
424:             }
425: 
426:             linksKeys.setPrivateKey(shareId, linkId, privateKey);
427:             return privateKey;
428:         }
429:     );
430: 
431:     /**
432:      * getLinkSessionKey returns the session key used for block encryption.
433:      */
434:     const getLinkSessionKey = debouncedFunctionDecorator(
435:         'getLinkSessionKey',
436:         async (abortSignal: AbortSignal, shareId: string, linkId: string): Promise<SessionKey> => {
437:             let sessionKey = linksKeys.getSessionKey(shareId, linkId);
438:             if (sessionKey) {
439:                 return sessionKey;
440:             }
441: 
442:             const encryptedLink = await getEncryptedLink(abortSignal, shareId, linkId);
443:             if (!encryptedLink.contentKeyPacket) {
444:                 // This is dev error, should not happen in the wild.
445:                 throw new Error('Content key is available only in file context');
446:             }
447: 
448:             const privateKey = await getLinkPrivateKey(abortSignal, shareId, linkId);
449: 
450:             const blockKeys = Uint8Array.fromBase64(encryptedLink.contentKeyPacket);
451: 
452:             try {
453:                 sessionKey = await getDecryptedSessionKey({
454:                     data: blockKeys,
455:                     privateKeys: privateKey,
456:                 });
457:             } catch (e) {
458:                 throw new EnrichedError('Failed to decrypt link session key', {
459:                     tags: {
460:                         shareId,
461:                         linkId,
462:                     },
463:                     extra: { e, crypto: true },
464:                 });
465:             }
466: 
467:             if (encryptedLink.contentKeyPacketSignature) {
468:                 const publicKeys = [privateKey, ...(await getVerificationKey(encryptedLink.signatureEmail))];
469:                 const { verificationStatus } = await CryptoProxy.verifyMessage({
470:                     binaryData: sessionKey.data,
471:                     verificationKeys: publicKeys,
472:                     armoredSignature: encryptedLink.contentKeyPacketSignature,
473:                 });
474:                 // iOS signed content key instead of session key in the past.
475:                 // Therefore we need to check that as well until we migrate
476:                 // old files.
477:                 if (verificationStatus !== VERIFICATION_STATUS.SIGNED_AND_VALID) {
478:                     const { verificationStatus: blockKeysVerified } = await CryptoProxy.verifyMessage({
479:                         binaryData: blockKeys,
480:                         verificationKeys: publicKeys,
481:                         armoredSignature: encryptedLink.contentKeyPacketSignature,
482:                     });
483:                     if (blockKeysVerified !== VERIFICATION_STATUS.SIGNED_AND_VALID) {
484:                         // If even fall back solution does not succeed, report
485:                         // the original verified status of the session key as
486:                         // that one is the one we want to verify here.
487:                         handleSignatureCheck(shareId, encryptedLink, 'contentKeyPacket', verificationStatus);
488:                     }
489:                 }
490:             }
491: 
492:             linksKeys.setSessionKey(shareId, linkId, sessionKey);
493:             return sessionKey;
494:         }
495:     );
496: 
497:     /**
498:      * getLinkHashKey returns the hash key used for checking name collisions.
499:      */
500:     const getLinkHashKey = debouncedFunctionDecorator(
501:         'getLinkHashKey',
502:         async (abortSignal: AbortSignal, shareId: string, linkId: string): Promise<Uint8Array<ArrayBuffer>> => {
503:             const cachedHashKey = linksKeys.getHashKey(shareId, linkId);
504:             if (cachedHashKey) {
505:                 return cachedHashKey;
506:             }
507: 
508:             const encryptedLink = await getEncryptedLink(abortSignal, shareId, linkId);
509:             if (!encryptedLink.nodeHashKey) {
510:                 // This is dev error, should not happen in the wild.
511:                 throw new Error('Hash key is available only in folder or albums context');
512:             }
513: 
514:             const [privateKey, addressPrivateKey] = await Promise.all([
515:                 getLinkPrivateKey(abortSignal, shareId, linkId),
516:                 getVerificationKey(encryptedLink.signatureEmail),
517:             ]);
518:             // In the past we had misunderstanding what key is used to sign
519:             // hash key. Originally it meant to be node key, which web used
520:             // for all links besides the root one, where address key was
521:             // used instead. Similarly, iOS or Android used address key for
522:             // all links. Latest versions should use node key in all cases
523:             // but we accept also address key. Its still signed with valid
524:             // key. In future we might re-sign bad links so we can get rid
525:             // of this.
526:             const publicKey = [privateKey, ...addressPrivateKey];
527: 
528:             try {
529:                 const { data: hashKey, verificationStatus } = await decryptSigned({
530:                     armoredMessage: encryptedLink.nodeHashKey,
531:                     privateKey,
532:                     publicKey,
533:                     format: 'binary',
534:                 });
535: 
536:                 if (
537:                     verificationStatus === VERIFICATION_STATUS.SIGNED_AND_INVALID ||
538:                     // The hash was not signed until Beta 17 (DRVWEB-1219).
539:                     (verificationStatus === VERIFICATION_STATUS.NOT_SIGNED &&
540:                         isAfter(fromUnixTime(encryptedLink.createTime), new Date(2021, 7, 1)))
541:                 ) {
542:                     handleSignatureCheck(shareId, encryptedLink, 'hash', verificationStatus);
543:                 }
544: 
545:                 linksKeys.setHashKey(shareId, linkId, hashKey);
546:                 return hashKey;
547:             } catch (e) {
548:                 throw new EnrichedError('Failed to decrypt link hash key', {
549:                     tags: {
550:                         shareId,
551:                         linkId,
552:                     },
553:                     extra: { e, crypto: true },
554:                 });
555:             }
556:         }
557:     );
558: 
559:     const getLinkRevision = async (
560:         abortSignal: AbortSignal,
561:         { shareId, linkId, revisionId }: { shareId: string; linkId: string; revisionId: string }
562:     ) => {
563:         const { Revision } = await debouncedRequest<DriveFileRevisionResult>(
564:             queryFileRevision(shareId, linkId, revisionId),
565:             abortSignal
566:         );
567:         return revisionPayloadToRevision(Revision);
568:     };
569: 
570:     /**
571:      * decryptLink decrypts provided `encryptedLink`. The result is not stored
572:      * anywhere, only returned back.
573:      */
574:     const decryptLink = async (
575:         abortSignal: AbortSignal,
576:         shareId: string,
577:         encryptedLink: EncryptedLink,
578:         revisionId?: string,
579:         share?: ShareWithKey | Share
580:     ): Promise<DecryptedLink> => {
581:         return debouncedFunction(
582:             async (abortSignal: AbortSignal): Promise<DecryptedLink> => {
583:                 let privateKey: PrivateKeyReference | undefined;
584:                 let privateKeyError;
585: 
586:                 try {
587:                     const parentPrivateKey: PrivateKeyReference = encryptedLink.parentLinkId
588:                         ? await getLinkPrivateKey(abortSignal, shareId, encryptedLink.parentLinkId)
589:                         : await getSharePrivateKey(abortSignal, shareId);
590: 
591:                     privateKey = parentPrivateKey;
592:                 } catch (e) {
593:                     privateKeyError = e;
594:                     // ignore failures but still report them to Sentry
595:                     sendErrorReport(e, {
596:                         extra: {
597:                             message: 'decryptLink() - Failed to get parentPrivateKey',
598:                         },
599:                     });
600:                 }
601: 
602:                 if (encryptedLink.photoProperties?.albums.length && !encryptedLink.parentLinkId) {
603:                     for (const album of encryptedLink.photoProperties.albums) {
604:                         try {
605:                             const albumPrivateKey = await getLinkPrivateKey(abortSignal, shareId, album.albumLinkId);
606:                             privateKey = albumPrivateKey;
607:                             // we can break at first album since it's enough to decrypt / for optimization
608:                             break;
