252:     /**
253:      * debouncedFunctionDecorator wraps original callback with debouncedFunction
254:      * to ensure that if even two or more calls with the same parameters are
255:      * executed only once. E.g., to not decrypt the same link keys twice.
256:      */
257:     const debouncedFunctionDecorator = <T>(
258:         cacheKey: string,
259:         callback: (abortSignal: AbortSignal, shareId: string, linkId: string) => Promise<T>
260:     ): ((abortSignal: AbortSignal, shareId: string, linkId: string) => Promise<T>) => {
261:         const wrapper = async (abortSignal: AbortSignal, shareId: string, linkId: string): Promise<T> => {
262:             return debouncedFunction(
263:                 async (abortSignal: AbortSignal) => {
264:                     return callback(abortSignal, shareId, linkId);
265:                 },
266:                 [cacheKey, shareId, linkId],
267:                 abortSignal
268:             );
269:         };
270:         return wrapper;
271:     };
