286:     /**
287:      * getLinkPassphraseAndSessionKey returns the passphrase with session key
288:      * used for locking the private key.
289:      */
290:     const getLinkPassphraseAndSessionKey = debouncedFunctionDecorator(
291:         'getLinkPassphraseAndSessionKey',
292:         async (
293:             abortSignal: AbortSignal,
294:             shareId: string,
295:             linkId: string
296:         ): Promise<{ passphrase: string; passphraseSessionKey: SessionKey; encryptedLink?: EncryptedLink }> => {
297:             const passphrase = linksKeys.getPassphrase(shareId, linkId);
298:             const sessionKey = linksKeys.getPassphraseSessionKey(shareId, linkId);
299:             if (passphrase && sessionKey) {
300:                 return { passphrase, passphraseSessionKey: sessionKey };
301:             }
302: 
303:             const encryptedLink = await getEncryptedLink(abortSignal, shareId, linkId);
304: 
305:             let privateKey: PrivateKeyReference | undefined;
306:             let privateKeyError;
307: 
308:             try {
309:                 const parentPrivateKey = encryptedLink.parentLinkId
310:                     ? // eslint-disable-next-line @typescript-eslint/no-use-before-define
311:                       await getLinkPrivateKey(abortSignal, shareId, encryptedLink.parentLinkId)
312:                     : await getSharePrivateKey(abortSignal, shareId);
313:                 privateKey = parentPrivateKey;
314:             } catch (e) {
315:                 privateKeyError = e;
316:                 // ignore failures but still report them to Sentry
317:                 sendErrorReport(e, {
318:                     extra: {
319:                         message: 'getLinkPassphraseAndSessionKey() - Failed to get parentPrivateKey',
320:                     },
321:                 });
322:             }
323: 
324:             if (encryptedLink.photoProperties?.albums.length && !encryptedLink.parentLinkId) {
325:                 for (const album of encryptedLink.photoProperties.albums) {
326:                     try {
327:                         // eslint-disable-next-line @typescript-eslint/no-use-before-define
328:                         const albumPrivateKey = await getLinkPrivateKey(abortSignal, shareId, album.albumLinkId);
329:                         privateKey = albumPrivateKey;
330:                         // we can break at first album since it's enough to decrypt / for optimization
331:                         break;
332:                     } catch (e) {
333:                         // ignore failures but still report them to Sentry
334:                         sendErrorReport(e, {
335:                             extra: {
336:                                 message: 'getLinkPassphraseAndSessionKey() - Failed to get albumPrivateKey',
337:                             },
338:                         });
339:                     }
340:                 }
341:             }
342: 
343:             if (!privateKey) {
344:                 if (abortSignal.aborted) {
345:                     throw privateKeyError;
346:                 }
347:                 // This should never happen. If you see this error in Sentry something is wrong
348:                 throw new EnrichedError('No private key was found during getLinkPassphraseAndSessionKey', {
349:                     tags: {
350:                         shareId,
351:                         linkId,
352:                     },
353:                     extra: { e: privateKeyError, crypto: true },
354:                 });
355:             }
356: 
357:             const addressPublicKey = encryptedLink.signatureEmail
358:                 ? await getVerificationKey(encryptedLink.signatureEmail)
359:                 : [];
360: 
361:             try {
362:                 // Fallback to parent NodeKey in case if we don't have addressPublicKey (Anonymous upload)
363:                 const publicKeysCallbackList: VerificationKeysCallback[] = [
364:                     async () => (encryptedLink.signatureEmail ? addressPublicKey : [privateKey]),
365:                 ];
366: 
367:                 const {
368:                     decryptedPassphrase,
369:                     sessionKey: passphraseSessionKey,
370:                     verificationStatus,
371:                 } = await decryptPassphrase({
372:                     armoredPassphrase: encryptedLink.nodePassphrase,
373:                     armoredSignature: encryptedLink.nodePassphraseSignature,
374:                     privateKeys: [privateKey],
375:                     publicKeysCallbackList,
376:                 });
377: 
378:                 handleSignatureCheck(shareId, encryptedLink, 'passphrase', verificationStatus);
379: 
380:                 linksKeys.setPassphrase(shareId, linkId, decryptedPassphrase);
381:                 linksKeys.setPassphraseSessionKey(shareId, linkId, passphraseSessionKey);
382: 
383:                 return {
384:                     passphrase: decryptedPassphrase,
385:                     passphraseSessionKey,
386:                     encryptedLink,
387:                 };
388:             } catch (e) {
389:                 throw new EnrichedError('Failed to decrypt link passphrase', {
390:                     tags: {
391:                         shareId,
392:                         linkId,
393:                     },
394:                     extra: { e, crypto: true },
395:                 });
396:             }
397:         }
398:     );
