400:     /**
401:      * getLinkPrivateKey returns the private key used for link meta data encryption.
402:      */
403:     const getLinkPrivateKey = debouncedFunctionDecorator(
404:         'getLinkPrivateKey',
405:         async (abortSignal: AbortSignal, shareId: string, linkId: string): Promise<PrivateKeyReference> => {
406:             let privateKey = linksKeys.getPrivateKey(shareId, linkId);
407:             if (privateKey) {
408:                 return privateKey;
409:             }
410: 
411:             // getLinkPassphraseAndSessionKey already call getEncryptedLink, prevent to call fetchLink twice
412:             let { passphrase, encryptedLink } = await getLinkPassphraseAndSessionKey(abortSignal, shareId, linkId);
413:             encryptedLink = encryptedLink || (await getEncryptedLink(abortSignal, shareId, linkId));
414:             try {
415:                 privateKey = await importPrivateKey({ armoredKey: encryptedLink.nodeKey, passphrase });
416:             } catch (e) {
417:                 throw new EnrichedError('Failed to import link private key', {
418:                     tags: {
419:                         shareId,
420:                         linkId,
421:                     },
422:                     extra: { e, crypto: true },
423:                 });
424:             }
425: 
426:             linksKeys.setPrivateKey(shareId, linkId, privateKey);
427:             return privateKey;
428:         }
