431:     /**
432:      * getLinkSessionKey returns the session key used for block encryption.
433:      */
434:     const getLinkSessionKey = debouncedFunctionDecorator(
435:         'getLinkSessionKey',
436:         async (abortSignal: AbortSignal, shareId: string, linkId: string): Promise<SessionKey> => {
437:             let sessionKey = linksKeys.getSessionKey(shareId, linkId);
438:             if (sessionKey) {
439:                 return sessionKey;
440:             }
441: 
442:             const encryptedLink = await getEncryptedLink(abortSignal, shareId, linkId);
443:             if (!encryptedLink.contentKeyPacket) {
444:                 // This is dev error, should not happen in the wild.
445:                 throw new Error('Content key is available only in file context');
446:             }
447: 
448:             const privateKey = await getLinkPrivateKey(abortSignal, shareId, linkId);
449: 
450:             const blockKeys = Uint8Array.fromBase64(encryptedLink.contentKeyPacket);
451: 
452:             try {
453:                 sessionKey = await getDecryptedSessionKey({
454:                     data: blockKeys,
455:                     privateKeys: privateKey,
456:                 });
457:             } catch (e) {
458:                 throw new EnrichedError('Failed to decrypt link session key', {
459:                     tags: {
460:                         shareId,
461:                         linkId,
462:                     },
463:                     extra: { e, crypto: true },
464:                 });
465:             }
466: 
467:             if (encryptedLink.contentKeyPacketSignature) {
468:                 const publicKeys = [privateKey, ...(await getVerificationKey(encryptedLink.signatureEmail))];
469:                 const { verificationStatus } = await CryptoProxy.verifyMessage({
470:                     binaryData: sessionKey.data,
471:                     verificationKeys: publicKeys,
472:                     armoredSignature: encryptedLink.contentKeyPacketSignature,
473:                 });
474:                 // iOS signed content key instead of session key in the past.
475:                 // Therefore we need to check that as well until we migrate
476:                 // old files.
477:                 if (verificationStatus !== VERIFICATION_STATUS.SIGNED_AND_VALID) {
478:                     const { verificationStatus: blockKeysVerified } = await CryptoProxy.verifyMessage({
479:                         binaryData: blockKeys,
480:                         verificationKeys: publicKeys,
481:                         armoredSignature: encryptedLink.contentKeyPacketSignature,
482:                     });
483:                     if (blockKeysVerified !== VERIFICATION_STATUS.SIGNED_AND_VALID) {
484:                         // If even fall back solution does not succeed, report
485:                         // the original verified status of the session key as
486:                         // that one is the one we want to verify here.
487:                         handleSignatureCheck(shareId, encryptedLink, 'contentKeyPacket', verificationStatus);
488:                     }
489:                 }
490:             }
491: 
492:             linksKeys.setSessionKey(shareId, linkId, sessionKey);
493:             return sessionKey;
494:         }
495:     );
