497:     /**
498:      * getLinkHashKey returns the hash key used for checking name collisions.
499:      */
500:     const getLinkHashKey = debouncedFunctionDecorator(
501:         'getLinkHashKey',
502:         async (abortSignal: AbortSignal, shareId: string, linkId: string): Promise<Uint8Array<ArrayBuffer>> => {
503:             const cachedHashKey = linksKeys.getHashKey(shareId, linkId);
504:             if (cachedHashKey) {
505:                 return cachedHashKey;
506:             }
507: 
508:             const encryptedLink = await getEncryptedLink(abortSignal, shareId, linkId);
509:             if (!encryptedLink.nodeHashKey) {
510:                 // This is dev error, should not happen in the wild.
511:                 throw new Error('Hash key is available only in folder or albums context');
512:             }
513: 
514:             const [privateKey, addressPrivateKey] = await Promise.all([
515:                 getLinkPrivateKey(abortSignal, shareId, linkId),
516:                 getVerificationKey(encryptedLink.signatureEmail),
517:             ]);
518:             // In the past we had misunderstanding what key is used to sign
519:             // hash key. Originally it meant to be node key, which web used
520:             // for all links besides the root one, where address key was
521:             // used instead. Similarly, iOS or Android used address key for
522:             // all links. Latest versions should use node key in all cases
523:             // but we accept also address key. Its still signed with valid
524:             // key. In future we might re-sign bad links so we can get rid
525:             // of this.
526:             const publicKey = [privateKey, ...addressPrivateKey];
527: 
528:             try {
529:                 const { data: hashKey, verificationStatus } = await decryptSigned({
530:                     armoredMessage: encryptedLink.nodeHashKey,
531:                     privateKey,
532:                     publicKey,
533:                     format: 'binary',
534:                 });
535: 
536:                 if (
537:                     verificationStatus === VERIFICATION_STATUS.SIGNED_AND_INVALID ||
538:                     // The hash was not signed until Beta 17 (DRVWEB-1219).
539:                     (verificationStatus === VERIFICATION_STATUS.NOT_SIGNED &&
540:                         isAfter(fromUnixTime(encryptedLink.createTime), new Date(2021, 7, 1)))
541:                 ) {
542:                     handleSignatureCheck(shareId, encryptedLink, 'hash', verificationStatus);
543:                 }
544: 
545:                 linksKeys.setHashKey(shareId, linkId, hashKey);
546:                 return hashKey;
547:             } catch (e) {
548:                 throw new EnrichedError('Failed to decrypt link hash key', {
549:                     tags: {
550:                         shareId,
551:                         linkId,
552:                     },
553:                     extra: { e, crypto: true },
554:                 });
555:             }
556:         }
557:     );
